if (!dir.exists("sims/results")) {
  dir.create("sims/results", recursive = TRUE)
}

# Plot 1: Coverage by mechanism and functional
p1 <- ggplot(coverage_summary, aes(x = mechanism, y = coverage,
                                   fill = functional)) +
  geom_col(position = "dodge", alpha = 0.8) +
  geom_hline(yintercept = 0.95, linetype = "dashed", color = "red") +
  geom_hline(yintercept = 0.90, linetype = "dotted", color = "orange") +
  facet_wrap(~lambda, labeller = label_both) +
  scale_y_continuous(labels = scales::percent, limits = c(0, 1.05)) +
  scale_fill_brewer(palette = "Set2", name = "Functional") +
  labs(
    title = "TV-Robustness: Coverage by Mechanism and Functional",
    subtitle = sprintf("Target: 95%% (red line) | N=%d reps per (λ, functional, mechanism)",
                       N_REPLICATIONS),
    x = "Q-Generation Mechanism",
    y = "Coverage Rate"
  ) +
  theme_minimal() +
  theme(axis.text.x = element_text(angle = 45, hjust = 1),
        legend.position = "bottom")

ggsave("sims/results/tv_robustness_coverage.png", p1,
       width = 12, height = 8, dpi = 300)
cat("  Saved: sims/results/tv_robustness_coverage.png\n")

# Plot 2: Empirical φ(Q) vs minimax bounds
p2 <- ggplot(all_results, aes(x = empirical_phi)) +
  geom_histogram(aes(fill = contained), bins = 30, alpha = 0.7) +
  geom_vline(aes(xintercept = minimax_lower), linetype = "dashed", color = "blue") +
  geom_vline(aes(xintercept = minimax_upper), linetype = "dashed", color = "blue") +
  facet_grid(mechanism ~ functional, scales = "free") +
  scale_fill_manual(values = c("TRUE" = "green", "FALSE" = "red"),
                    labels = c("TRUE" = "Contained", "FALSE" = "Violated")) +
  labs(
    title = "Distribution of Empirical φ(Q) Across Mechanisms",
    subtitle = "Blue lines: minimax bounds [φ_*, φ*]",
    x = "Empirical φ(Q)",
    y = "Count",
    fill = "Contained?"
  ) +
  theme_minimal(base_size = 8) +
  theme(legend.position = "bottom")

ggsave("sims/results/tv_robustness_distribution.png", p2,
       width = 14, height = 10, dpi = 300)
cat("  Saved: sims/results/tv_robustness_distribution.png\n")

# Plot 3: Violation scatter (if any)
if (nrow(violations) > 0) {
  p3 <- ggplot(violations, aes(x = empirical_phi, y = minimax_upper - minimax_lower)) +
    geom_point(aes(color = mechanism), size = 3, alpha = 0.7) +
    facet_wrap(~functional, scales = "free") +
    labs(
      title = "Bound Violations: Where Did Minimax Fail?",
      subtitle = "Points represent (φ(Q), bound_width) for violations",
      x = "Empirical φ(Q) (outside bounds)",
      y = "Bound Width",
      color = "Mechanism"
    ) +
    theme_minimal()

  ggsave("sims/results/tv_robustness_violations.png", p3,
         width = 10, height = 6, dpi = 300)
  cat("  Saved: sims/results/tv_robustness_violations.png\n")
}

# Save detailed results
saveRDS(all_results, "sims/results/tv_robustness_detailed.rds")
cat("\n  Saved: sims/results/tv_robustness_detailed.rds\n")

saveRDS(coverage_summary, "sims/results/tv_robustness_summary.rds")
cat("  Saved: sims/results/tv_robustness_summary.rds\n")

cat("\n")
cat("================================================================\n")
cat("PAPER IMPLICATIONS\n")
cat("================================================================\n\n")

if (overall_coverage >= 0.95) {
  cat("**KEY FINDING**: TV distance is sufficient!\n\n")

  cat("Result:\n")
  cat(sprintf("  Minimax bounds achieved %.1f%% coverage across ALL mechanisms,\n",
              overall_coverage * 100))
  cat("  including covariate shift, selection bias, extreme perturbations,\n")
  cat("  and adversarial Q generation. This validates the paper's central claim:\n\n")

  cat("  'For ANY future study Q with d_TV(Q, P₀) ≤ λ, the minimax bounds\n")
  cat("   [φ_*, φ*] contain the true surrogate quality φ(Q) with high probability.\n")
  cat("   This guarantee holds regardless of HOW Q differs from P₀—whether through\n")
  cat("   covariate shift, selection bias, or other mechanisms—so long as the\n")
  cat("   total variation distance constraint is satisfied.'\n\n")

  cat("Mechanism Performance:\n")
  for (i in 1:nrow(coverage_by_mechanism)) {
    row <- coverage_by_mechanism[i, ]
    cat(sprintf("  - %s: %.1f%% coverage\n", row$mechanism, row$coverage * 100))
  }

  cat("\nStrength of Claim:\n")
  cat("  This is the STRONGEST validation: bounds hold model-free, beyond mixture assumption.\n")

} else if (overall_coverage >= 0.90) {
  cat("Finding:\n")
  cat("  Most mechanisms respected bounds (≥90% coverage).\n")
  cat(sprintf("  Worst mechanism: %s (%.1f%%)\n",
              worst_mechanism$mechanism, worst_mechanism$coverage * 100))
  cat("\n  Recommendation: Report overall coverage with mechanism breakdown.\n")

} else {
  cat("**CONCERN**: Some mechanisms violate bounds.\n\n")

  cat("Failures:\n")
  mech_failures <- coverage_by_mechanism %>% filter(coverage < 0.90)
  for (i in 1:nrow(mech_failures)) {
    row <- mech_failures[i, ]
    cat(sprintf("  - %s: %.1f%% coverage (FAIL)\n",
                row$mechanism, row$coverage * 100))
  }

  cat("\nAction Items:\n")
  cat("  1. Increase n_dirichlet_grid for finer search\n")
  cat("  2. Add vertices back (include_vertices = TRUE)\n")
  cat("  3. Investigate: Is TV distance miscalculated for some mechanisms?\n")
  cat("  4. Consider: Is class M rich enough for all mechanisms?\n")
}

